const BANNER2_URL="https://raw.githubusercontent.com/YOONSOEUN1/hometwo/main/images/banner2.png";

const BRAND_URL="https://raw.githubusercontent.com/YOONSOEUN1/hometwo/main/images/hometwostudy.png";

// ============================================================
// 내 썸네일 사진 (GitHub images 폴더): image1.jpg ~ image30.jpg
// 사진 개수가 다르면 THUMB_COUNT, 확장자가 다르면 THUMB_EXT 만 바꾸세요.
// ============================================================
const THUMB_BASE = "https://raw.githubusercontent.com/YOONSOEUN1/hometwo/main/images/";
const THUMB_COUNT = 30;
const THUMB_EXT   = ".jpg";
const THUMBS = [];
for (let i = 1; i <= THUMB_COUNT; i++) THUMBS.push(THUMB_BASE + "image" + i + THUMB_EXT);
function pickThumb(seed){ return THUMBS[(seed >>> 0) % THUMBS.length]; }
function hashStr(s){ s=String(s||""); let h=2166136261; for(let i=0;i<s.length;i++){ h^=s.charCodeAt(i); h=Math.imul(h,16777619); } return h>>>0; }
function thumbFor(key){ return pickThumb(hashStr(key)); }
function thumbImg(key, alt, style){ return '<img src="'+thumbFor(key)+'" alt="'+(alt||'홈투과외')+'" loading="lazy" style="'+(style||'width:100%;height:100%;object-fit:cover;display:block;')+'" onerror="this.style.display=\'none\';">'; }
function thumbGallery(count){
 var n = Math.min(count||THUMB_COUNT, THUMB_COUNT);
 var out = '<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px;">';
 for(var i=1;i<=n;i++){
  out += '<a href="'+THUMB_BASE+'image'+i+THUMB_EXT+'" target="_blank" rel="noopener" style="display:block;border-radius:12px;overflow:hidden;aspect-ratio:4/3;background:#EFF1F8;border:1px solid #E3E7F0;">'
      +  '<img src="'+THUMB_BASE+'image'+i+THUMB_EXT+'" alt="홈투과외 수업 사진 '+i+'" loading="lazy" style="width:100%;height:100%;object-fit:cover;display:block;transition:transform .3s;" onmouseover="this.style.transform=\'scale(1.05)\'" onmouseout="this.style.transform=\'scale(1)\'" onerror="this.parentElement.style.display=\'none\';">'
      +  '</a>';
 }
 return out+'</div>';
}
