 // 시드 기반 선택
 const pick = (pool, count, offset) => {
  const result = [];
  const used = new Set();
  for (let i = 0; i < count; i++) {
   let idx = (seed + offset + i * 7) % pool.length;
   while (used.has(idx)) idx = (idx + 1) % pool.length;
   used.add(idx);
   result.push(pool[idx]);
  }
  return result;
 };

