function buildAllSiteUrls() {
 // IndexNow용 핵심 페이지 (사이트맵과 동일한 전략)
 // 약 3,500개로 집중 → 네이버가 중요 페이지로 인식
 const base = "https://" + SITE_HOST;
 const urls = [base + "/", base + "/directory", base + "/schools", base + "/academy", base + "/subject", base + "/language"];
 // 학년별 페이지
 for (const gc of Object.keys(GRADE_DATA)) {
  urls.push(base + "/grade/" + gc);
  for (const sj of ["국어","영어","수학","사회","과학","코딩","논술","검정고시"]) {
   urls.push(base + "/grade/" + gc + "/" + encodeURIComponent(sj));
  }
 }
 // 과목별 페이지
 for (const k of SUBJECT_LIST) {
  urls.push(base + "/subject/" + SUBJECTS[k].slug);
 }
 // 외국어 페이지
 for (const l of ["english","japanese","chinese"]) {
  urls.push(base + "/language/" + l);
 }
 // 17개 지역 + 모든 시군구 + 핵심 동/학교
 for (const [rs, ri] of Object.entries(locations)) {
  urls.push(base + "/" + rs);
  urls.push(base + "/schools/" + rs);
  // 지역 × 과목 페이지
  for (const sj of ["국어","영어","수학","사회","과학","코딩","논술","검정고시"]) {
   urls.push(base + "/" + rs + "/subject/" + encodeURIComponent(sj));
  }
  for (const [cs, ci] of Object.entries(ri.cities)) {
   urls.push(base + "/" + rs + "/" + cs);
   urls.push(base + "/" + rs + "/" + cs + "/schools");
   // 시군구당 상위 5개 동만
   (ci.dongs || []).slice(0,5).forEach(function(d){
    urls.push(base + "/" + rs + "/" + cs + "/" + encodeURIComponent(d));
   });
   // 시군구당 상위 3개 학교만
   (ci.schools || []).slice(0,3).forEach(function(sch){
    urls.push(base + "/" + rs + "/" + cs + "/school/" + encodeURIComponent(sch.n || sch));
   });
  }
 }
 // 학원 메인 페이지만 (서브 페이지 제외 - 색인 집중)
 ACAD_DETAIL.forEach(function(ct) {
  urls.push(base + "/academy/" + encodeURIComponent(ct.sl));
 });
 return urls;
}

async function submitIndexNowChunk(urlList) {
 const body = {
 host: SITE_HOST,
 key: INDEXNOW_KEY,
 keyLocation: "https://" + SITE_HOST + "/" + INDEXNOW_KEY + ".txt",
 urlList: urlList
 };
 try {
 // Naver + Bing + Yandex + IndexNow.org 동시 제출
 const resp = await fetch("https://searchadvisor.naver.com/indexnow", {
 method: "POST",
 headers: {"Content-Type": "application/json; charset=utf-8"},
 body: JSON.stringify(body)
 });
 let respText = "";
 try { respText = await resp.text(); } catch(e) {}
 // Bing에도 제출
 try { await fetch("https://www.bing.com/indexnow", {
 method: "POST",
 headers: {"Content-Type": "application/json; charset=utf-8"},
 body: JSON.stringify(body)
 }); } catch(e) {}
 // Yandex에도 제출
 try { await fetch("https://yandex.com/indexnow", {
 method: "POST",
 headers: {"Content-Type": "application/json; charset=utf-8"},
 body: JSON.stringify(body)
 }); } catch(e) {}
 // IndexNow.org에도 제출
 try { await fetch("https://api.indexnow.org/indexnow", {
 method: "POST",
 headers: {"Content-Type": "application/json; charset=utf-8"},
 body: JSON.stringify(body)
 }); } catch(e) {}
 return {status: resp.status, count: urlList.length, body: respText.slice(0, 200)};
 } catch (e) {
 return {status: "ERROR", count: urlList.length, error: e.message};
 }
}

function handleSearch(q) {
 if (!q) return {redirect:"/directory"};
 const kws = q.split(/\s+/).filter(Boolean);
 const qns = q.replace(/\s+/g,"");
 // 1) 학교명 정확 매칭 (완전 일치 우선)
 for (const [rs,ri] of Object.entries(locations)) {
 for (const [cs,ci] of Object.entries(ri.cities)) {
 for (const sch of (ci.schools||[])) {
 if (sch.replace(/\s/g,"") === qns) {
 return {redirect:"/"+rs+"/"+cs+"/school/"+encodeURIComponent(sch)};
 }
 }
 }
 }
 // 2) 학교명 부분 매칭 (입력이 학교명에 포함)
 for (const [rs,ri] of Object.entries(locations)) {
 for (const [cs,ci] of Object.entries(ri.cities)) {
 for (const sch of (ci.schools||[])) {
 const sn = sch.replace(/\s/g,"");
 if (sn.includes(qns) && qns.length>=2) {
 return {redirect:"/"+rs+"/"+cs+"/school/"+encodeURIComponent(sch)};
 }
 }
 }
 }
 // 3) 동네/시·구 매칭
 for (const [rs,ri] of Object.entries(locations)) {
 const rn = ri.region_name, sr = rn.slice(0,2);
 for (const [cs,ci] of Object.entries(ri.cities)) {
 const cn = ci.name, sc = cn.length>2?cn.slice(0,-1):cn;
 const target = rn+" "+cn+" "+(ci.dongs||[]).join(" ");
 if (kws.every(k=>target.includes(k))) return {redirect:"/"+rs+"/"+cs};
 for (const d of (ci.dongs||[])) {
 if (qns.includes(d.replace(/\s/g,""))&&(qns.includes(sr)||qns.includes(sc)||qns.includes(cn)))
 return {redirect:"/"+rs+"/"+cs};
 }
 }
 }
 for (const [rs,ri] of Object.entries(locations)) {
 if (kws.every(k=>ri.region_name.includes(k))) return {redirect:"/directory#"+encodeURIComponent(ri.region_name)};
 }
 return {notFound:q};
}

function handleSuggest(q) {
 if (!q) return [];
 const qns = q.replace(/\s+/g,"");
 const res=[], seen=new Set();
 // 학교 매칭 우선 표시
 for (const [rs,ri] of Object.entries(locations)) {
 const sr=ri.region_name.slice(0,2);
 for (const [cs,ci] of Object.entries(ri.cities)) {
 const cn=ci.name;
 for (const sch of (ci.schools||[])) {
 if (sch.replace(/\s/g,"").includes(qns)) {
 const k="🏫 "+sr+" "+cn+" "+sch;
 if(!seen.has(k)){
 seen.add(k);
 res.push({display:k,url:"/"+rs+"/"+cs+"/school/"+encodeURIComponent(sch)});
 }
 if(res.length>=7)break;
 }
 }
 if(res.length>=7)break;
 }
 if(res.length>=7)break;
 }
 // 동네/시 매칭
 for (const [rs,ri] of Object.entries(locations)) {
 const rn=ri.region_name, sr=rn.slice(0,2);
 for (const [cs,ci] of Object.entries(ri.cities)) {
 const cn=ci.name, sc=cn.length>2?cn.slice(0,-1):cn;
 const md=(ci.dongs||[]).filter(d=>d.replace(/\s/g,"").includes(qns));
 if (md.length>0) {
 const k="📍 "+sr+" "+cn+" "+md[0];
 if(!seen.has(k)){seen.add(k);res.push({display:k,url:"/"+rs+"/"+cs});}
 } else if(cn.includes(qns)||sc.includes(qns)) {
 const k="📍 "+rn+" "+cn;
 if(!seen.has(k)){seen.add(k);res.push({display:k,url:"/"+rs+"/"+cs});}
 }
 if(res.length>=7)break;
 }
 if(res.length>=7)break;
 }
 return res.slice(0,7);
}


