const LANG_SUBS = {
 english:[
  {slug:"conversation",icon:"🗣",t:"영어 회화 수업",desc:"일상·여행·비즈니스 상황별 영어 회화를 1:1로 집중 훈련합니다",
   content:"영어 회화 수업은 학생이 실제 생활에서 마주하는 다양한 상황을 중심으로 설계됩니다. 카페에서 주문하기, 공항에서 체크인하기, 호텔에서 요청하기, 택시에서 목적지 말하기 등 실생활에서 즉시 활용할 수 있는 표현을 반복적으로 훈련합니다. 홈투과외의 1:1 영어 회화 수업은 학생의 현재 수준을 정밀하게 진단한 뒤, 왕초보부터 고급자까지 맞춤형 커리큘럼을 제공합니다. 수업의 70% 이상이 학생이 직접 말하는 시간으로 구성되어 있어, 듣기만 하는 수업과는 차원이 다른 학습 효과를 경험할 수 있습니다. 롤플레이, 실전 시뮬레이션, 즉석 대화 연습 등 다양한 방법을 활용하며, 매 수업 후에는 복습 자료와 음성 피드백을 제공하여 수업 외 시간에도 효과적으로 연습할 수 있도록 지원합니다. 특히 한국인이 어려워하는 발음 교정, 억양 훈련, 필러(um, uh) 줄이기 등 세밀한 부분까지 1:1로 집중 코칭합니다."},
  {slug:"exam",icon:"📝",t:"영어 자격증 대비",desc:"토익스피킹·오픽·IELTS·토플 등 영어 말하기 시험 집중 대비",
   content:"영어 자격증 시험은 체계적인 전략과 반복 훈련이 합격의 핵심입니다. 홈투과외의 영어 자격증 대비 수업은 토익 스피킹, 오픽(OPIc), IELTS 스피킹, 토플 스피킹 등 각 시험별 출제 유형을 철저히 분석하고, 고득점을 위한 답변 구조와 표현 패턴을 집중적으로 훈련합니다. 단순히 시험 기술만 가르치는 것이 아니라, 실제 말하기 실력을 근본적으로 향상시켜 어떤 유형의 문제가 나와도 유연하게 대응할 수 있는 능력을 키웁니다. 시험별로 최적화된 모의시험을 정기적으로 실시하고, 녹음 분석을 통해 발음·유창성·문법·어휘 등 세부 항목별 피드백을 제공합니다. 목표 점수 달성까지 밀착 관리하며, 시험 직전에는 파이널 모의시험과 핵심 정리 특강을 진행합니다. 토익 스피킹 Lv.7+, 오픽 IH~AL, IELTS 6.5+ 등 구체적인 목표 점수에 맞춘 맞춤 플랜을 제공합니다."},
  {slug:"video",icon:"💻",t:"영어 화상·전화 과외",desc:"어디서든 편하게, 1:1 화상·전화 영어 수업으로 실력 향상",
   content:"바쁜 일정 속에서도 영어 실력을 꾸준히 향상시키고 싶은 분들을 위한 화상·전화 과외 프로그램입니다. 출퇴근 시간, 점심시간, 저녁 시간 등 학생의 라이프스타일에 맞춰 유연하게 수업 시간을 조율할 수 있습니다. 줌(Zoom), 구글 미트 등 화상 플랫폼을 활용한 수업은 대면 수업과 동일한 수준의 상호작용이 가능하며, 화면 공유를 통한 교재 학습, 실시간 채팅을 활용한 표현 정리 등 온라인만의 장점을 최대한 활용합니다. 전화 수업은 이동 중에도 참여할 수 있어 시간 활용도가 극대화되며, 오직 듣기와 말하기에만 집중하기 때문에 리스닝과 스피킹 능력이 빠르게 향상됩니다. 모든 수업은 녹화 또는 녹음이 가능하여 수업 후 복습에 활용할 수 있으며, 수업 후에는 카카오톡으로 과제와 피드백을 전달받아 지속적인 학습이 이루어집니다."},
  {slug:"method",icon:"📋",t:"영어 수업 방식 안내",desc:"홈투과외만의 체계적인 영어 학습 시스템을 소개합니다",
   content:"홈투과외의 영어 수업은 과학적이고 체계적인 학습 시스템을 기반으로 운영됩니다. 첫 번째 단계는 정밀 레벨 테스트입니다. 단순한 문법 시험이 아니라, 실제 대화를 통해 발음·유창성·어휘력·문법 정확도·의사소통 능력을 종합적으로 평가합니다. 이를 바탕으로 학생 개인에게 최적화된 학습 로드맵을 설계합니다. 두 번째 단계는 맞춤 수업 진행입니다. 매 수업은 복습(10분) → 새 표현 학습(15분) → 실전 연습(25분) → 정리 및 피드백(10분)의 구조로 진행되며, 학생이 최대한 많이 말할 수 있도록 설계되어 있습니다. 세 번째 단계는 지속 관리입니다. 수업 후 카카오톡으로 수업 요약과 과제를 전달하고, 학생의 학습 진도와 약점을 주간 리포트로 분석합니다. 월 1회 레벨 재평가를 통해 성장 정도를 객관적으로 확인하고, 필요시 커리큘럼을 조정합니다. 이 모든 과정이 학생 한 명 한 명에게 맞춤으로 이루어집니다."}],
 japanese:[
  {slug:"conversation",icon:"🗣",t:"일본어 회화 수업",desc:"생활·여행·비즈니스 일본어 회화를 1:1로 집중 훈련합니다",
   content:"일본어 회화 수업은 한국인의 언어적 특성을 최대한 활용하여 가장 효율적인 방법으로 진행됩니다. 한국어와 일본어는 문법 구조가 거의 동일하기 때문에, 영어처럼 어순을 바꿔 생각할 필요가 없습니다. 이 장점을 살려 처음부터 문장 단위로 말하기 훈련을 시작합니다. 인사, 자기소개, 쇼핑, 식당 주문, 교통 이용, 호텔 체크인 등 실생활에서 자주 만나는 상황을 롤플레이 방식으로 반복 훈련하여, 일본에 가서 바로 사용할 수 있는 실전 회화력을 키웁니다. 특히 일본어 특유의 경어 체계(존경어·겸양어·정중어)는 한국인이 가장 어려워하는 부분이지만, 실제 사용 빈도가 높은 표현부터 자연스럽게 익히도록 설계하여 부담 없이 학습할 수 있습니다. 애니메이션, 드라마, 뉴스 등 학생이 관심 있는 콘텐츠를 수업에 적극 활용하여 학습 동기를 높이고, 자연스러운 구어체 표현까지 함께 익힐 수 있습니다."},
  {slug:"exam",icon:"📝",t:"JLPT·자격증 대비",desc:"JLPT N5~N1, JPT, NAT-TEST 등 일본어 자격증 시험 집중 대비",
   content:"JLPT(일본어능력시험)는 일본 유학, 취업, 비자 발급 등에서 가장 널리 인정받는 자격증입니다. 홈투과외의 JLPT 대비 수업은 N5부터 N1까지 각 급수별 출제 유형을 10년치 기출문제 분석을 바탕으로 체계적으로 학습합니다. 문법·어휘·독해·청해 4개 영역을 균형 있게 다루되, 학생의 약점 영역에 더 많은 시간을 할당하는 맞춤형 학습 플랜을 운영합니다. 특히 청해 영역은 단순 듣기가 아니라 일본인의 자연스러운 발화 속도와 축약 표현에 익숙해지는 훈련을 진행하며, 독해 영역은 빠른 시간 안에 핵심을 파악하는 스키밍·스캐닝 기법을 집중적으로 연습합니다. 시험 2주 전부터는 실전과 동일한 조건의 모의시험을 실시하고, 채점 후 약점 분석과 최종 보완 학습을 진행합니다. JPT, NAT-TEST 등 다른 일본어 자격증 시험도 대비 가능합니다."},
  {slug:"video",icon:"💻",t:"일본어 화상·전화 과외",desc:"어디서든 편하게, 1:1 화상·전화 일본어 수업",
   content:"일본어 화상·전화 과외는 시간과 장소의 제약 없이 꾸준히 일본어 실력을 향상시킬 수 있는 프로그램입니다. 줌, 구글 미트 등 화상 플랫폼을 통해 대면 수업과 동일한 품질의 1:1 수업을 받을 수 있으며, 화면 공유를 활용한 교재 학습, 실시간 필기 피드백, 발음 교정 등 온라인 수업만의 장점을 최대한 활용합니다. 전화 수업은 통화만으로 진행되기 때문에 오직 듣기와 말하기에 집중할 수 있어, 특히 청해 능력과 즉시 응답 능력이 빠르게 향상됩니다. 출퇴근 시간, 점심시간, 잠자기 전 등 자투리 시간을 활용할 수 있어 바쁜 직장인과 학생에게 최적의 학습 방법입니다. 모든 수업은 녹화·녹음이 가능하여 복습에 활용할 수 있으며, 수업 후 카카오톡으로 수업 정리 노트와 과제를 전달받습니다. 주 2~3회 꾸준한 수업으로 3개월 내 눈에 띄는 실력 변화를 경험할 수 있습니다."},
  {slug:"method",icon:"📋",t:"일본어 수업 방식 안내",desc:"홈투과외만의 체계적인 일본어 학습 시스템",
   content:"홈투과외의 일본어 수업은 한국인 학습자에게 최적화된 독자적인 학습 시스템으로 운영됩니다. 첫 수업 전에 무료 레벨 테스트를 실시하여 현재 수준을 정확하게 파악하고, 학습 목표와 가용 시간을 고려한 개인별 학습 로드맵을 설계합니다. 수업은 복습 확인(10분) → 새 내용 학습(15분) → 반복 연습 및 롤플레이(20분) → 정리 및 다음 수업 예고(5분)의 50분 구조로 진행됩니다. 한국어와 일본어의 유사점을 적극 활용하여 학습 효율을 극대화하며, 한자어 대조 학습법으로 어휘력을 빠르게 확장합니다. 수업 후에는 카카오톡으로 수업 요약, 새 어휘 정리, 과제를 전달하고, 학생이 제출한 과제에 대해 상세한 피드백을 제공합니다. 월 1회 레벨 재평가와 학습 상담을 통해 진도를 점검하고, 필요시 커리큘럼을 조정하여 최적의 학습 경로를 유지합니다."}],
 chinese:[
  {slug:"conversation",icon:"🗣",t:"중국어 회화 수업",desc:"생활·여행·비즈니스 중국어 회화를 1:1로 집중 훈련합니다",
   content:"중국어 회화 수업에서 가장 중요한 것은 성조입니다. 같은 발음이라도 성조가 다르면 완전히 다른 뜻이 되기 때문에, 홈투과외의 중국어 회화 수업은 초기 2~4주를 성조 집중 교정 기간으로 설정합니다. 1:1 수업이기 때문에 학생의 발음을 실시간으로 교정할 수 있어, 학원이나 그룹 수업에서는 불가능한 세밀한 발음 지도가 이루어집니다. 성조가 안정된 후에는 인사, 자기소개, 쇼핑, 식당 주문, 택시 이용, 호텔 체크인 등 실생활 상황별 회화를 집중 훈련합니다. 중국인이 실제로 사용하는 구어체 표현과 유행어도 함께 다루어, 교과서 중국어가 아닌 살아있는 중국어를 배울 수 있습니다. 비즈니스 중국어가 필요한 직장인을 위해서는 무역 용어, 미팅 표현, 이메일·전화 응대 등 실무 중심의 수업도 운영합니다. 중국의 지역별 발음 차이와 문화적 뉘앙스까지 함께 배울 수 있어, 중국 현지에서 바로 통용되는 자연스러운 중국어를 완성합니다."},
  {slug:"exam",icon:"📝",t:"HSK·자격증 대비",desc:"HSK 1~6급, HSKK, BCT 등 중국어 자격증 시험 집중 대비",
   content:"HSK(한어수평고시)는 중국 유학, 취업, 장학금 신청 등에서 가장 공신력 있는 중국어 자격증입니다. 홈투과외의 HSK 대비 수업은 1급부터 6급까지 각 급수별 출제 경향을 철저히 분석하고, 듣기·독해·작문(4급 이상) 영역을 균형 있게 학습합니다. 급수별 필수 어휘를 체계적으로 정리하고(1급 150자 → 6급 5,000자), 기출문제 패턴 분석을 통해 효율적인 풀이 전략을 수립합니다. 특히 듣기 영역은 중국인의 자연스러운 발화 속도에 적응하는 훈련을 중점적으로 진행하며, 독해 영역은 빈출 문법 패턴과 어휘를 집중적으로 다룹니다. HSK 5~6급의 작문 영역은 정해진 시간 내에 논리적인 글을 작성하는 연습을 반복합니다. 실전 모의시험을 정기적으로 실시하고, 채점 후 약점 분석과 보완 학습을 진행합니다. HSKK(구술시험), BCT(비즈니스 중국어시험) 등 특수 자격증도 대비 가능합니다."},
  {slug:"video",icon:"💻",t:"중국어 화상·전화 과외",desc:"어디서든 편하게, 1:1 화상·전화 중국어 수업",
   content:"중국어 화상·전화 과외는 장소와 시간에 구애받지 않고 꾸준히 중국어 실력을 키울 수 있는 프로그램입니다. 특히 중국어는 성조가 핵심이기 때문에, 화상 수업에서 강사의 입 모양과 표정을 직접 보면서 발음을 교정받는 것이 매우 효과적입니다. 줌, 구글 미트 등을 활용한 화상 수업에서는 화면 공유를 통한 한자 필기 연습, 실시간 병음 교정, 교재 학습 등이 원활하게 이루어집니다. 전화 수업은 듣기와 말하기에만 집중하기 때문에 특히 청해 능력과 즉각적인 응답 능력이 빠르게 향상됩니다. 매 수업 후에는 카카오톡으로 수업 정리 노트, 새 어휘와 문장, 과제를 전달받아 복습할 수 있습니다. 바쁜 직장인을 위한 이른 아침·늦은 저녁 수업, 주말 집중 수업 등 유연한 시간 조율이 가능합니다."},
  {slug:"method",icon:"📋",t:"중국어 수업 방식 안내",desc:"홈투과외만의 체계적인 중국어 학습 시스템",
   content:"홈투과외의 중국어 수업은 한국인 학습자의 특성을 고려한 독자적인 학습 시스템으로 운영됩니다. 첫 수업 전 무료 레벨 테스트에서 발음(성조 정확도), 어휘력, 문법 이해도, 회화 능력을 종합적으로 평가합니다. 이를 바탕으로 학습 목표(여행·취업·유학·자격증)와 가용 시간을 고려한 개인별 학습 로드맵을 설계합니다. 수업은 성조·발음 점검(5분) → 지난 수업 복습(10분) → 새 내용 학습(15분) → 반복 연습 및 대화 훈련(15분) → 정리(5분)의 50분 구조로 진행됩니다. 한국인이 이미 알고 있는 한자 지식을 적극 활용하는 한자 대조 학습법으로 어휘를 효율적으로 확장하며, 병음과 한자를 동시에 학습하여 읽기·말하기·쓰기 능력을 균형 있게 발전시킵니다. 수업 후에는 카카오톡으로 수업 요약, 새 어휘, 과제를 전달하고, 음성 메시지를 활용한 발음 과제도 진행합니다."}]
};
